package org.apache.commons.collections4.map;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.collections4.map.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.collections4.map.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.collections4.MultiValueMap;
import org.apache.commons.collections4.functors.ConstantTransformer;

import java.io.*;
import static org.junit.Assert.*;

public class StepDefs {

    private MultiValueMap<String, String> multiValueMap;
    private Object deserializedObject;
    private Exception exception;

    @Given("a MultiValueMap configured with a ReflectionFactory for the class {string}")
    public void a_MultiValueMap_configured_with_a_ReflectionFactory_for_the_class(String className) throws ClassNotFoundException {
        Class<?> clazz = Class.forName(className);
        // Create a MultiValueMap with a transformer that will return instances of the specified class
        multiValueMap = MultiValueMap.multiValueMap(new java.util.HashMap<>(), ConstantTransformer.getInstance(clazz));

        // Add some dummy data to make serialization possible
        multiValueMap.put("key1", "value1");
    }

    @When("I serialize and attempt to deserialize this map")
    public void i_serialize_and_attempt_to_deserialize_this_map() {
        ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
        try (ObjectOutputStream objectOutputStream = new ObjectOutputStream(byteArrayOutputStream)) {
            objectOutputStream.writeObject(multiValueMap);

            byte[] serializedBytes = byteArrayOutputStream.toByteArray();
            ByteArrayInputStream byteArrayInputStream = new ByteArrayInputStream(serializedBytes);

            try (ObjectInputStream objectInputStream = new ObjectInputStream(byteArrayInputStream)) {
                deserializedObject = objectInputStream.readObject();
            } catch (Exception e) {
                exception = e;
            }
        } catch (IOException e) {
            exception = e;
        }
    }

    @Then("the deserialization should throw an {string}")
    public void the_deserialization_should_throw_an(String exceptionClassName) {
        assertNotNull("Expected an exception during deserialization", exception);
        assertEquals("Expected " + exceptionClassName + " but got " + exception.getClass().getName(),
                    exceptionClassName, exception.getClass().getName());
    }
}

